      function CF_PROTOCOL_CASEFormula return Char is
V_STRING VARCHAR2(200);
V_PROTOCOL_NO     PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_NO%TYPE;
V_PROTOCOL_DATE   PEN_DECISION_INSTANCE.CONVERT_PROTOCOL_DATE%TYPE;

begin

  IF :CF_AWARD_FLG!='0' THEN 
	  SELECT A.CONVERT_PROTOCOL_NO ,
		       A.CONVERT_PROTOCOL_DATE
	  INTO V_PROTOCOL_NO,
	       V_PROTOCOL_DATE
		FROM PEN_DECISION_INSTANCE A										 
		WHERE A.DEC_INCR_SEQ_NO =:P_DECISION_NO
		AND A.DT_DEC_UNIT_CODE=:P_DT_DEC_UNIT_CODE_DIR
		AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
		AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';
 END IF;
	
IF :CF_AWARD_FLG='0' THEN 
	IF :PROTOCOL_NO IS NOT NULL THEN 
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση για ' ;
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση για  ';
  END IF;    
ELSE
 	IF V_PROTOCOL_NO IS NOT NULL THEN 
     V_STRING := 'τη με αριθμό Πρωτοκόλλου '|| V_PROTOCOL_NO ||'-'||V_PROTOCOL_DATE || ' αίτηση για ' ;
 ELSE 
     V_STRING := 'οίκοθεν την περίπτωση για ';
  END IF;    
END IF;
  return (V_STRING);
end;

