      function CF_REASONFormula return Char is

v_DESCR  VARCHAR2(100);
v_calc_begin_date_varchar   VARCHAR2(10);
v_calc_begin_date_varchar1  VARCHAR2(10);
v_DESCR1  VARCHAR2(100);

CURSOR cur_pension_type IS 
SELECT D.PROCUCT_DESCRIPTION
FROM PEN_QC_PER_PRODINST A,
PEN_PRODUCT_PER_INSTITUTIONS B,
PEN_ACCOUNT  C,
PEN_PRODUCTS D
WHERE  C.ACCOUNT_NO= v_calc_begin_date_varchar
AND C.QCPRODINS_QC_PER_PRODINST_CODE=A.QC_PER_PRODINST_CODE
AND A.PRODUCT_PER_INSTITUTION_CODE=B.PRODUCT_PER_INSTITUTION_CODE
AND B.PRODUCT_CODE = D.PRODUCT_CODE;

CURSOR cur_pension IS 
SELECT D.PROCUCT_DESCRIPTION
FROM PEN_PRODUCTS D
WHERE D.PRODUCT_CODE = v_calc_begin_date_varchar1;
	     

begin

v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
             0,0,'00001','01181','01127');

v_calc_begin_date_varchar1 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
             0,0,'00001','01180','01011');



  open cur_pension_type;
  fetch cur_pension_type
  into v_DESCR;
  close cur_pension_type;

  open cur_pension;
  fetch cur_pension
  into v_DESCR1;
  close cur_pension;                         
                         
  IF  V_DESCR IS NOT NULL THEN
  	  RETURN V_DESCR;
  ELSE 	  
    RETURN V_DESCR1;
   END IF; 
  
end;

      function CF_INSURANCE_DAYSFormula return Number is

 V_RESULT NUMBER;
 V_YEAR   NUMBER;

CURSOR cur_INS_DAYS IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00500';

CURSOR cur_YEAR IS
SELECT INSURANCE_YEARS
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;


begin

  OPEN cur_INS_DAYS;
  FETCH cur_INS_DAYS
  INTO V_RESULT;
  CLOSE cur_INS_DAYS;
  
  OPEN cur_YEAR;
  FETCH cur_YEAR
  INTO V_YEAR;
  CLOSE cur_YEAR;
  
  
   IF :P_Acc_Account_No_DIR IS NOT NULL THEN 
        RETURN ROUND(V_YEAR*300);
   ELSE                                                            
   	 RETURN V_RESULT;
   END IF; 
  
end;

