      function CF_INS_DATE return Date is
 V_RESULT DATE;
 V_ACCOUNT_DECEASED  NUMBER;
 v_calc_begin_date_varchar_1 VARCHAR2(10);
 
CURSOR cur_ACCOUNT_DECEASED IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_ACC_ACCOUNT_NO_DIR AND
       A.Title_Code         = '01181' AND
	     A.Dec_Fact_Type_Code = '01127';

CURSOR cur_DATE IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = V_ACCOUNT_DECEASED AND
       A.Title_Code         =  '00367' AND
	     A.Dec_Fact_Type_Code =  '00506';

begin
	OPEN cur_ACCOUNT_DECEASED;
	FETCH cur_ACCOUNT_DECEASED
	INTO V_ACCOUNT_DECEASED;
	CLOSE cur_ACCOUNT_DECEASED;
  
  OPEN cur_DATE;
  FETCH cur_DATE
  INTO V_RESULT;
  CLOSE cur_DATE;
  
  v_calc_begin_date_varchar_1 := Find_Fact_Sub_Death_Varchar(:P_INSURED_ID,:P_DT_DECISION_YEAR_DIR,:P_DT_DEC_UNIT_CODE_DIR,:P_DT_INCR_SEC_NO_DIR, '1',
            0,0,'00001','01180','00662');

  
  IF  V_RESULT IS NOT NULL THEN
  	RETURN V_RESULT;
  ELSE
  	RETURN v_calc_begin_date_varchar_1;
  END IF;	
end;

