      function CF_ANNOUNCEMENTFormula return Char is
V_BRANCH_CODE VARCHAR2(5);
V_BRANCH_NAME VARCHAR2(50);

BEGIN
  V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00172','00247');
  IF V_BRANCH_CODE IS NULL THEN
	  V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
				 0,0,'00001','00069','00247');            
