cursor Cur_Fact_Subtype_Existance_2 IS select distinct pen_dec_fact_types_instance.value from pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.title_code='01069' AND pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00584' UNION select distinct pen_dec_fact_types_instance.value ---EE-DS from pen_dec_fact_types_instance WHERE pen_dec_fact_types_instance.title_code='99111' AND pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1' AND pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_SR AND pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND pen_dec_fact_types_instance.dec_fact_type_code = '00584' ;
V_DEATH_REASON VARCHAR2(20); begin to_return :=''; v_iban:=null; open Cur_Fact_Subtype_Existance; fetch Cur_Fact_Subtype_Existance into v_iban; close Cur_Fact_Subtype_Existance; open Cur_Fact_Subtype_Existance_2; fetch Cur_Fact_Subtype_Existance_2 into V_DEATH_REASON; close Cur_Fact_Subtype_Existance_2; if v_iban is not null then IF V_DEATH_REASON='1' THEN to_Return:='Πληρωμή Σύνταξης χωρίς πίστωση σε Τραπεζικό Λογαριασμό.'; ELSE to_Return:='Πληρωμή Σύνταξης με πίστωση σε Τραπεζικό Λογαριασμό.'; END IF; end if; return to_Return;
end;

      function CF_DATESFormula return Char is
TO_RETURN VARCHAR2(1000);
CURSOR FETC_START_DATE IS
SELECT value 
  FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00025','00157') AND 
pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR  AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
pen_dec_fact_types_instance.dec_fact_type_code IN ( '00040');

CURSOR FETC_END_DATE IS
SELECT value 
  FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00025','00157') AND 
pen_dec_fact_types_instance.ins_insured_id= :P_INSURED_ID_IND AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR  AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
pen_dec_fact_types_instance.dec_fact_type_code IN ( '00041');

V_START_DATE DATE;
V_END_DATE DATE;
begin
	TO_RETURN:=:VALUE3;
	OPEN FETC_START_DATE;
	FETCH FETC_START_DATE INTO V_START_DATE;
	CLOSE FETC_START_DATE;
	
  OPEN FETC_END_DATE;
	FETCH FETC_END_DATE INTO V_END_DATE;
	CLOSE FETC_END_DATE;
	
	IF V_START_DATE IS NOT NULL AND V_END_DATE IS NOT NULL THEN
		TO_RETURN:=TO_RETURN||' Από '||V_START_DATE||' έως '|| V_end_DATE;
	end if;
	IF V_START_DATE IS NOT NULL AND V_END_DATE IS  NULL THEN
		TO_RETURN:=TO_RETURN||' Από '||V_START_DATE;
	end if;
	IF V_START_DATE IS  NULL AND V_END_DATE IS NOT NULL THEN
		TO_RETURN:=TO_RETURN||' Έως '|| V_end_DATE;
	end if;

	
  RETURN TO_RETURN;
end;

