function AfterPForm return boolean is
CURSOR C1 IS SELECT COM_ORG_BRANCHES.BRANCH_NAME FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_BE_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR;
cursor c_wrk is select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid from wrk_decisions a where a.status = '1' and a.pen_unit = :P_DT_DEC_UNIT_CODE and a.pen_year = :P_DT_DECISION_YEAR and a.pen_no = :P_DEC_INCR_SEC_NO ;
L_DEC_NO varchar2(50);
Begin
OPEN C1; FETCH C1 INTO :P_BRANCH_NAME; CLOSE C1;
open c_wrk; fetch c_wrk into :P_WRK_DEC_NO; close c_wrk;
return (TRUE);
end;

      -- CHRYS 10/5/2021
function CF_146Formula return Number is
begin
  RETURN NVL( :CF_48*(:P_PERCENTAGE/100) * :CF_36/100,0);
end;
-- END CHRYS 10/5/2021

function CF_DEPENDENCTY_TYPEFormula return Char is
CURSOR C1 IS SELECT --PEN_DECISION_INSTANCE_DEATH.Dependency_Type --PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec PEN_DEPENDANT_TYPES.dependency_name FROM PEN_DECISION_INSTANCE_DEATH, PEN_APPLICATION_INSTANCES, PEN_DEPENDANT_TYPES WHERE PEN_APPLICATION_INSTANCES.Pdta_Application_Year =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Year AND PEN_APPLICATION_INSTANCES.Pdta_Application_Unit_Code =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Unit_Code AND PEN_APPLICATION_INSTANCES.Application_Incr_Seq_No =PEN_DECISION_INSTANCE_DEATH.Application_Incr_Seq_No AND PEN_APPLICATION_INSTANCES.Pdta_Document_Type_Appl_Code=PEN_DECISION_INSTANCE_DEATH.Pdta_Document_Type_Appl_Code AND PEN_DEPENDANT_TYPES.dependency_type =PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec AND PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO =:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE =:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR =:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID =:P_INSURED_ID ;
L_DESCR VARCHAR2(200); begin OPEN C1; FETCH C1 INTO L_DESCR; CLOSE C1; RETURN (L_DESCR); end;
